// ComposeCreateTableSql emits a ClickHouse-compatible CREATE TABLE
// statement for runtime.facts. Drop-in replacement for the historical
// factsschema.ComposeCreateTableSql — same signature, same semantics,
// but with the column block baked at codegen time so no leeway pipeline
// runs at process startup.
func ComposeCreateTableSql(engineClause string) (sql string, err error) {
	if engineClause == "" {
		err = eh.Errorf("compose ddl: empty engine clause")
		return
	}
	var b strings.Builder
	fmt.Fprintf(&b, "CREATE DATABASE IF NOT EXISTS %s;\nCREATE TABLE IF NOT EXISTS %s.%s (\n", DatabaseName, DatabaseName, TableName)
	b.WriteString(ColumnsSQL)
	fmt.Fprintf(&b, "\n) ENGINE %s\nSETTINGS %s;\n", engineClause, SettingsClause)
	sql = b.String()
	return
}
